Modified greedy insertion with time-window feasibility check, fallback to best available assign even if non-empty, and post-insertion route regeneration.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderIndices := make([]int, len(oris))
	for i := range orderIndices {
		orderIndices[i] = i
	}
	rand.Shuffle(len(orderIndices), func(i, j int) {
		orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
	})
	assignOrder := make([]int, MAXASSIGNS)
	assignLimit := 0
	for i := 0; i < MAXASSIGNS; i++ {
		assignOrder[i] = i
		if i < dispatch.AssignsLen && dispatch.Assigns[i].StationsLen > 0 {
			assignOrder[assignLimit], assignOrder[i] = assignOrder[i], assignOrder[assignLimit]
			assignLimit++
		}
	}
	rand.Shuffle(assignLimit, func(i, j int) {
		assignOrder[i], assignOrder[j] = assignOrder[j], assignOrder[i]
	})
	fallbackIndices := make([]int, MAXASSIGNS)
	for i := 0; i < MAXASSIGNS; i++ {
		fallbackIndices[i] = i
	}
	rand.Shuffle(MAXASSIGNS, func(i, j int) {
		fallbackIndices[i], fallbackIndices[j] = fallbackIndices[j], fallbackIndices[i]
	})
	for _, oi := range orderIndices {
		inserted := false
		bestIdx := -1
		bestCostDelta := math.MaxFloat64
		oldCosts := make([]float64, MAXASSIGNS)
		for k := 0; k < MAXASSIGNS; k++ {
			idx := assignOrder[k%len(assignOrder)]
			if idx >= MAXASSIGNS {
				continue
			}
			if k == 0 || idx < dispatch.AssignsLen {
				oldCosts[idx] = dispatch.Assigns[idx].Cost
				if dispatch.Assigns[idx].AddShip(total_ship+oi, oris[oi], dess[oi]) {
					dispatch.Assigns[idx].GenRoute()
					if dispatch.Assigns[idx].Cost >= 0 {
						costDelta := dispatch.Assigns[idx].Cost - oldCosts[idx]
						if costDelta < bestCostDelta {
							bestCostDelta = costDelta
							bestIdx = idx
						}
					}
					dispatch.Assigns[idx].RemoveShip(total_ship + oi)
					dispatch.Assigns[idx].Cost = oldCosts[idx]
					dispatch.Assigns[idx].GenRoute()
				}
			}
		}
		if bestIdx >= 0 {
			success := dispatch.Assigns[bestIdx].AddShip(total_ship+oi, oris[oi], dess[oi])
			if success {
				dispatch.Assigns[bestIdx].GenRoute()
				if dispatch.Assigns[bestIdx].Cost >= 0 {
					if bestIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen = bestIdx + 1
						if dispatch.AssignsLen > MAXASSIGNS {
