						}
					}
					inserted = true
				} else {
					dispatch.Assigns[bestIdx].RemoveShip(total_ship + oi)
					dispatch.Assigns[bestIdx].GenRoute()
				}
			}
		}
		if !inserted {
			for _, fi := range fallbackIndices {
				if fi >= MAXASSIGNS {
					continue
				}
				if dispatch.Assigns[fi].AddShip(total_ship+oi, oris[oi], dess[oi]) {
					dispatch.Assigns[fi].GenRoute()
					if dispatch.Assigns[fi].Cost >= 0 {
